  1→//! Forth debugger component — COR24 emulator with Forth-aware inspection.
  2→
  3→use crate::config::{ForthTier, StackSize};
  4→use cor24_emulator::{Assembler, EmulatorCore};
  5→use gloo::timers::callback::Timeout;
  6→use std::collections::VecDeque;
  7→use web_sys::{HtmlElement, HtmlInputElement};
  8→use yew::prelude::*;
  9→
 10→/// Execution batch size per tick (instructions).
 11→const BATCH_SIZE: u64 = 50_000;
 12→
 13→/// Tick interval in milliseconds.
 14→const TICK_MS: u32 = 25;
 15→
 16→pub enum Msg {
 17→    /// Load and start the emulator.
 18→    Init,
 19→    /// Run a batch of instructions.
 20→    Tick,
 21→    /// User typed in the input bar.
 22→    InputChanged(String),
 23→    /// User pressed Enter to send input.
 24→    SendInput,
 25→    /// Switch Forth tier.
 26→    SetTier(ForthTier),
 27→    /// Switch stack size.
 28→    SetStack(StackSize),
 29→    /// Reset emulator.
 30→    Reset,
 31→    /// Step one instruction.
 32→    Step,
 33→    /// Step over (run until return from call).
 34→    StepOver,
 35→    /// Toggle run/pause.
 36→    PauseResume,
 37→    /// Handle keydown in input field.
 38→    InputKeyDown(KeyboardEvent),
 39→}
 40→
 41→pub struct Debugger {
 42→    emulator: EmulatorCore,
 43→    tier: ForthTier,
 44→    stack_size: StackSize,
 45→    output: String,
 46→    input: String,
 47→    running: bool,
 48→    halted: bool,
 49→    /// Pending timeout handle (kept alive to prevent cancel).
 50→    _tick_handle: Option<Timeout>,
 51→    /// Previous register values for change highlighting.
 52→    prev_regs: [u32; 8],
 53→    prev_pc: u32,
 54→    /// Pending UART RX bytes to feed one-at-a-time.
 55→    uart_rx_queue: VecDeque<u8>,
 56→    /// Ref to output div for auto-scroll.
 57→    output_ref: NodeRef,
 58→}
 59→
 60→impl Debugger {
 61→    fn load_binary(&mut self, _ctx: &Context<Self>) {
 62→        let mut asm = Assembler::new();
 63→        let result = asm.assemble(self.tier.assembly());
 64→
 65→        if !result.errors.is_empty() {
 66→            self.output = "Assembly errors:\n".to_string();
 67→            for e in &result.errors {
 68→                self.output.push_str(e);
 69→                self.output.push('\n');
 70→            }
 71→            return;
 72→        }
 73→
 74→        self.emulator.hard_reset();
 75→        self.emulator.load_program(0, &result.bytes);
 76→        self.emulator.load_program_extent(result.bytes.len() as u32);
 77→        self.emulator.set_pc(0);
 78→        self.output.clear();
 79→        self.halted = false;
 80→        self.prev_regs = [0; 8];
 81→        self.prev_pc = 0;
 82→        self.uart_rx_queue.clear();
 83→
 84→        // Start paused — debugger mode.
 85→        self.running = false;
 86→        self.emulator.pause();
 87→    }
 88→
 89→    fn schedule_tick(&mut self, ctx: &Context<Self>) {
 90→        let link = ctx.link().clone();
 91→        self._tick_handle = Some(Timeout::new(TICK_MS, move || {
 92→            link.send_message(Msg::Tick);
 93→        }));
 94→    }
 95→
 96→    fn snapshot_regs(&self) -> [u32; 8] {
 97→        let snap = self.emulator.snapshot();
 98→        snap.regs
 99→    }
100→
101→    fn read_data_stack(&self) -> Vec<u32> {
102→        let sp = self.emulator.snapshot().regs[4]; // sp = r4
103→        let stack_top = self.stack_size.initial_sp();
104→        let mut cells = Vec::new();
105→        let mut addr = stack_top;
106→        // Stack grows downward; entries are from stack_top-3 down to sp.
107→        while addr > sp && cells.len() < 64 {
108→            addr -= 3; // cell = 3 bytes
109→            let val = self.emulator.read_word(addr);
110→            cells.push(val & 0xFFFFFF);
111→        }
112→        cells.reverse(); // bottom of stack first
113→        cells
114→    }
115→
116→    fn read_return_stack(&self) -> Vec<u32> {
117→        let rsp = self.emulator.snapshot().regs[1]; // r1 = RSP
118→        let rstack_base: u32 = 0x0F0000;
119→        let mut cells = Vec::new();
120→        let mut addr = rstack_base;
121→        while addr > rsp && cells.len() < 64 {
122→            addr -= 3;
123→            let val = self.emulator.read_word(addr);
124→            cells.push(val & 0xFFFFFF);
125→        }
126→        cells.reverse();
127→        cells
128→    }
129→
130→    /// Disassemble instructions around the current PC.
131→    fn disassemble_around_pc(
132→        &self,
133→        count_before: usize,
134→        count_after: usize,
135→    ) -> Vec<(u32, String, bool)> {
136→        let pc = self.emulator.snapshot().pc;
137→        // Disassemble forward from PC to get the current + after
138→        let forward = self.emulator.disassemble(pc, count_after + 1);
139→
140→        // For instructions before PC, scan backwards heuristically.
141→        // COR24 has variable-length instructions (1, 2, or 4 bytes).
142→        // Walk backwards by trying offsets.
143→        let mut before = Vec::new();
144→        if count_before > 0 && pc > 0 {
145→            // Collect candidate addresses by scanning backwards
146→            let scan_start = pc.saturating_sub((count_before as u32) * 4 + 8);
147→            let all = self.emulator.disassemble(scan_start, 128);
148→            // Find instructions that end at or before PC
149→            for &(addr, ref mnemonic, size) in &all {
150→                if addr < pc {
151→                    before.push((addr, mnemonic.clone(), size));
152→                } else {
153→                    break;
154→                }
155→            }
156→            // Take only the last count_before
157→            let skip = before.len().saturating_sub(count_before);
158→            before = before.into_iter().skip(skip).collect();
159→        }
160→
161→        let mut result: Vec<(u32, String, bool)> = Vec::new();
162→        for (addr, mnemonic, _size) in before {
163→            result.push((addr, mnemonic, false));
164→        }
165→        for (addr, mnemonic, _size) in forward {
166→            result.push((addr, mnemonic, addr == pc));
167→        }
168→        result
169→    }
170→
171→    /// Feed one byte from the UART RX queue if the UART is ready.
172→    fn feed_uart_byte(&mut self) {
173→        if self.uart_rx_queue.is_empty() {
174→            return;
175→        }
176→        // Check if UART RX buffer can accept (status register bit 0)
177→        let status = self.emulator.read_byte(0xFF0101);
178→        if status & 0x01 == 0 {
179→            // UART ready to receive — feed one byte
180→            if let Some(byte) = self.uart_rx_queue.pop_front() {
181→                self.emulator.send_uart_byte(byte);
182→            }
183→        }
184→    }
185→
186→    /// Collect UART output and auto-scroll.
187→    fn collect_uart_output(&mut self) {
188→        let uart = self.emulator.get_uart_output();
189→        if !uart.is_empty() {
190→            self.output.push_str(uart);
191→            self.emulator.clear_uart_output();
192→        }
193→    }
194→
195→    fn auto_scroll(&self) {
196→        if let Some(el) = self.output_ref.cast::<HtmlElement>() {
197→            el.set_scroll_top(el.scroll_height());
198→        }
199→    }
200→}
201→
202→impl Component for Debugger {
203→    type Message = Msg;
204→    type Properties = ();
205→
206→    fn create(ctx: &Context<Self>) -> Self {
207→        ctx.link().send_message(Msg::Init);
208→        Self {
209→            emulator: EmulatorCore::new(),
210→            tier: ForthTier::Bootstrap,
211→            stack_size: StackSize::ThreeKb,
212→            output: String::new(),
213→            input: String::new(),
214→            running: false,
215→            halted: false,
216→            _tick_handle: None,
217→            prev_regs: [0; 8],
218→            prev_pc: 0,
219→            uart_rx_queue: VecDeque::new(),
220→            output_ref: NodeRef::default(),
221→        }
222→    }
223→
224→    fn update(&mut self, ctx: &Context<Self>, msg: Self::Message) -> bool {
225→        match msg {
226→            Msg::Init => {
227→                self.load_binary(ctx);
228→                true
229→            }
230→
231→            Msg::Tick => {
232→                if !self.running {
233→                    return false;
234→                }
235→
236→                // Save previous state for change highlighting.
237→                self.prev_regs = self.snapshot_regs();
238→                self.prev_pc = self.emulator.snapshot().pc;
239→
240→                // Feed pending UART input bytes (poll-before-feed).
241→                self.feed_uart_byte();
242→
243→                let _result = self.emulator.run_batch(BATCH_SIZE);
244→
245→                // Collect UART output.
246→                self.collect_uart_output();
247→
248→                if self.emulator.is_halted() {
249→                    self.running = false;
250→                    self.halted = true;
251→                } else if self.running {
252→                    self.schedule_tick(ctx);
253→                }
254→
255→                true
256→            }
257→
258→            Msg::InputChanged(val) => {
259→                self.input = val;
260→                false
261→            }
262→
263→            Msg::SendInput => {
264→                if self.input.is_empty() {
265→                    return false;
266→                }
267→                // Queue bytes for poll-before-feed delivery.
268→                for b in self.input.bytes() {
269→                    self.uart_rx_queue.push_back(b);
270→                }
271→                self.uart_rx_queue.push_back(b'\n');
272→                self.input.clear();
273→
274→                if !self.running && !self.halted {
275→                    self.running = true;
276→                    self.emulator.resume();
277→                    self.schedule_tick(ctx);
278→                }
279→                true
280→            }
281→
282→            Msg::SetTier(tier) => {
283→                self.tier = tier;
284→                self.load_binary(ctx);
285→                true
286→            }
287→
288→            Msg::SetStack(size) => {
289→                self.stack_size = size;
290→                self.load_binary(ctx);
291→                true
292→            }
293→
294→            Msg::Reset => {
295→                self.load_binary(ctx);
296→                true
297→            }
298→
299→            Msg::Step => {
300→                if self.halted {
301→                    return false;
302→                }
303→                self.running = false;
304→                self.emulator.resume();
305→
306→                self.prev_regs = self.snapshot_regs();
307→                self.prev_pc = self.emulator.snapshot().pc;
308→
309→                self.feed_uart_byte();
310→                let _result = self.emulator.step();
311→                self.collect_uart_output();
312→
313→                self.emulator.pause();
314→                if self.emulator.is_halted() {
315→                    self.halted = true;
316→                }
317→                true
318→            }
319→
320→            Msg::StepOver => {
321→                if self.halted {
322→                    return false;
323→                }
324→                self.running = false;
325→                self.emulator.resume();
326→
327→                self.prev_regs = self.snapshot_regs();
328→                self.prev_pc = self.emulator.snapshot().pc;
329→
330→                self.feed_uart_byte();
331→                let _result = self.emulator.step_over();
332→                self.collect_uart_output();
333→
334→                self.emulator.pause();
335→                if self.emulator.is_halted() {
336→                    self.halted = true;
337→                }
338→                true
339→            }
340→
341→            Msg::PauseResume => {
342→                if self.halted {
343→                    return false;
344→                }
345→                if self.running {
346→                    self.running = false;
347→                    self.emulator.pause();
348→                    self._tick_handle = None;
349→                } else {
350→                    self.running = true;
351→                    self.emulator.resume();
352→                    self.schedule_tick(ctx);
353→                }
354→                true
355→            }
356→
357→            Msg::InputKeyDown(e) => {
358→                if e.key() == "Enter" {
359→                    ctx.link().send_message(Msg::SendInput);
360→                }
361→                false
362→            }
363→        }
364→    }
365→
366→    fn rendered(&mut self, _ctx: &Context<Self>, _first_render: bool) {
367→        self.auto_scroll();
368→    }
369→
370→    fn view(&self, ctx: &Context<Self>) -> Html {
371→        let snap = self.emulator.snapshot();
372→        let data_stack = self.read_data_stack();
373→        let return_stack = self.read_return_stack();
374→        let disasm = self.disassemble_around_pc(4, 8);
375→
376→        let reg_names = [
377→            "r0/W", "r1/RSP", "r2/IP", "r3/fp", "sp/DSP", "r5/zc", "r6/iv", "r7/ir",
378→        ];
379→
380→        html! {
381→            <div class="debugger">
382→                // Toolbar
383→                <div class="toolbar">
384→                    <button onclick={ctx.link().callback(|_| Msg::PauseResume)}
385→                            class={if self.running { "active" } else { "" }}>
386→                        { if self.running { "Pause" } else { "Run" } }
387→                    </button>
388→                    <button onclick={ctx.link().callback(|_| Msg::Step)}
389→                            disabled={self.running || self.halted}>
390→                        {"Step"}
391→                    </button>
392→                    <button onclick={ctx.link().callback(|_| Msg::StepOver)}
393→                            disabled={self.running || self.halted}>
394→                        {"Step Over"}
395→                    </button>
396→                    <button onclick={ctx.link().callback(|_| Msg::Reset)}>
397→                        {"Reset"}
398→                    </button>
399→
400→                    <select onchange={ctx.link().callback(|e: Event| {
401→                        let select: HtmlInputElement = e.target_unchecked_into();
402→                        let tier = match select.value().as_str() {
403→                            "Bootstrap" => ForthTier::Bootstrap,
404→                            _ => ForthTier::Bootstrap,
405→                        };
406→                        Msg::SetTier(tier)
407→                    })}>
408→                        { for ForthTier::ALL.iter().map(|t| {
409→                            html! {
410→                                <option value={t.label()} selected={*t == self.tier}>
411→                                    { t.label() }
412→                                </option>
413→                            }
414→                        })}
415→                    </select>
416→
417→                    <select onchange={ctx.link().callback(|e: Event| {
418→                        let select: HtmlInputElement = e.target_unchecked_into();
419→                        let size = match select.value().as_str() {
420→                            "3 KB" => StackSize::ThreeKb,
421→                            _ => StackSize::EightKb,
422→                        };
423→                        Msg::SetStack(size)
424→                    })}>
425→                        { for StackSize::ALL.iter().map(|s| {
426→                            html! {
427→                                <option value={s.label()} selected={*s == self.stack_size}>
428→                                    { s.label() }
429→                                </option>
430→                            }
431→                        })}
432→                    </select>
433→
434→                    <span class="tier-desc">{ self.tier.description() }</span>
435→                </div>
436→
437→                // Main panels
438→                <div class="panels">
439→                    // Output / terminal
440→                    <div class="output-panel">
441→                        <div class="output" ref={self.output_ref.clone()}>{ &self.output }</div>
442→                        <div class="input-bar">
443→                            <span class="prompt">{"> "}</span>
444→                            <input
445→                                type="text"
446→                                value={self.input.clone()}
447→                                oninput={ctx.link().callback(|e: InputEvent| {
448→                                    let input: HtmlInputElement = e.target_unchecked_into();
449→                                    Msg::InputChanged(input.value())
450→                                })}
451→                                onkeydown={ctx.link().callback(Msg::InputKeyDown)}
452→                                placeholder="Type Forth input..."
453→                            />
454→                        </div>
455→                    </div>
456→
457→                    // Side panel: registers + stacks
458→                    <div class="side-panel">
459→                        // CPU Registers
460→                        <div class="panel-section">
461→                            <h3>{"Registers"}</h3>
462→                            <div class="registers">
463→                                <span class="reg-name">{"PC"}</span>
464→                                <span class={classes!(
465→                                    "reg-value",
466→                                    (snap.pc != self.prev_pc).then_some("changed")
467→                                )}>
468→                                    { format!("{:06X}", snap.pc) }
469→                                </span>
470→                                { for (0..8).map(|i| {
471→                                    let changed = snap.regs[i] != self.prev_regs[i];
472→                                    html! {
473→                                        <>
474→                                            <span class="reg-name">{ reg_names[i] }</span>
475→                                            <span class={classes!(
476→                                                "reg-value",
477→                                                changed.then_some("changed")
478→                                            )}>
479→                                                { format!("{:06X}", snap.regs[i] & 0xFFFFFF) }
480→                                            </span>
481→                                        </>
482→                                    }
483→                                })}
484→                                <span class="reg-name">{"C"}</span>
485→                                <span class="reg-value">
486→                                    { if snap.c { "1" } else { "0" } }
487→                                </span>
488→                            </div>
489→                        </div>
490→
491→                        // Data Stack
492→                        <div class="panel-section">
493→                            <h3>{ format!("Data Stack ({})", data_stack.len()) }</h3>
494→                            <div class="stack-display">
495→                                { if data_stack.is_empty() {
496→                                    html! { <span class="stack-empty">{"(empty)"}</span> }
497→                                } else {
498→                                    html! {
499→                                        { for data_stack.iter().enumerate().map(|(i, val)| {
500→                                            let is_tos = i == data_stack.len() - 1;
501→                                            html! {
502→                                                <div class="stack-entry">
503→                                                    <span class="stack-index">
504→                                                        { format!("[{}]", i) }
505→                                                    </span>
506→                                                    <span class="stack-value">
507→                                                        { format!("{:06X}  {}", val, val) }
508→                                                    </span>
509→                                                    { if is_tos {
510→                                                        html! { <span class="stack-tos">{"<- TOS"}</span> }
511→                                                    } else {
512→                                                        html! {}
513→                                                    }}
514→                                                </div>
515→                                            }
516→                                        })}
517→                                    }
518→                                }}
519→                            </div>
520→                        </div>
521→
522→                        // Return Stack
523→                        <div class="panel-section">
524→                            <h3>{ format!("Return Stack ({})", return_stack.len()) }</h3>
525→                            <div class="stack-display">
526→                                { if return_stack.is_empty() {
527→                                    html! { <span class="stack-empty">{"(empty)"}</span> }
528→                                } else {
529→                                    html! {
530→                                        { for return_stack.iter().enumerate().map(|(i, val)| {
531→                                            let is_top = i == return_stack.len() - 1;
532→                                            html! {
533→                                                <div class="stack-entry">
534→                                                    <span class="stack-index">
535→                                                        { format!("[{}]", i) }
536→                                                    </span>
537→                                                    <span class="stack-value">
538→                                                        { format!("{:06X}  {}", val, val) }
539→                                                    </span>
540→                                                    { if is_top {
541→                                                        html! { <span class="stack-tos">{"<- TOP"}</span> }
542→                                                    } else {
543→                                                        html! {}
544→                                                    }}
545→                                                </div>
546→                                            }
547→                                        })}
548→                                    }
549→                                }}
550→                            </div>
551→                        </div>
552→
553→                        // LED + status
554→                        <div class="panel-section">
555→                            <h3>{"Hardware"}</h3>
556→                            <div class="registers">
557→                                <span class="reg-name">{"LED"}</span>
558→                                <span class="reg-value">
559→                                    <span class={classes!(
560→                                        "led",
561→                                        (snap.led != 0).then_some("on")
562→                                    )}></span>
563→                                </span>
564→                                <span class="reg-name">{"Cycles"}</span>
565→                                <span class="reg-value">{ format!("{}", snap.cycles) }</span>
566→                                <span class="reg-name">{"Instrs"}</span>
567→                                <span class="reg-value">{ format!("{}", snap.instructions) }</span>
568→                            </div>
569→                        </div>
570→
571→                        // Disassembly
572→                        <div class="panel-section">
573→                            <h3>{"Disassembly"}</h3>
574→                            <div class="disasm-view">
575→                                { for disasm.iter().map(|(addr, mnemonic, is_current)| {
576→                                    html! {
577→                                        <div class={classes!(
578→                                            "disasm-line",
579→                                            is_current.then_some("disasm-current")
580→                                        )}>
581→                                            <span class="disasm-addr">
582→                                                { format!("{:06X}", addr) }
583→                                            </span>
584→                                            <span class="disasm-instr">
585→                                                { mnemonic }
586→                                            </span>
587→                                        </div>
588→                                    }
589→                                })}
590→                            </div>
591→                        </div>
592→                    </div>
593→                </div>
594→
595→                // Status bar
596→                <div class="status-bar">
597→                    <div class="status-item">
598→                        <span class="status-label">{"Status:"}</span>
599→                        <span class="status-value">
600→                            { if self.halted { "Halted" }
601→                              else if self.running { "Running" }
602→                              else { "Paused" }
603→                            }
604→                        </span>
605→                    </div>
606→                    <div class="status-item">
607→                        <span class="status-label">{"PC:"}</span>
608→                        <span class="status-value">{ format!("0x{:06X}", snap.pc) }</span>
609→                    </div>
610→                    <div class="status-item">
611→                        <span class="status-label">{"Tier:"}</span>
612→                        <span class="status-value">{ self.tier.label() }</span>
613→                    </div>
614→                    <div class="status-item">
615→                        <span class="status-label">{"Stack:"}</span>
616→                        <span class="status-value">{ self.stack_size.label() }</span>
617→                    </div>
618→                </div>
619→            </div>
620→        }
621→    }
622→}
