/* Debugger layout */
.debugger {
    flex: 1;
    display: flex;
    flex-direction: column;
    overflow: hidden;
    min-height: 0;
}

/* Toolbar */
.toolbar {
    display: flex;
    align-items: center;
    gap: 8px;
    padding: 8px 20px;
    border-bottom: 1px solid var(--border);
    flex-shrink: 0;
    flex-wrap: wrap;
}

.toolbar button {
    background: var(--surface);
    color: var(--text);
    border: 1px solid var(--border);
    border-radius: 4px;
    padding: 4px 12px;
    font-family: var(--mono);
    font-size: 13px;
    cursor: pointer;
    transition: background 0.15s;
}

.toolbar button:hover {
    background: var(--border);
}

.toolbar button.active {
    background: var(--accent);
    color: var(--bg);
    border-color: var(--accent);
}

.toolbar select {
    background: var(--surface);
    color: var(--text);
    border: 1px solid var(--border);
    border-radius: 4px;
    padding: 4px 8px;
    font-family: var(--mono);
    font-size: 13px;
}

.toolbar .tier-desc {
    font-size: 12px;
    color: var(--dim);
    margin-left: 4px;
}

/* Main panels */
.panels {
    flex: 1;
    display: flex;
    overflow: hidden;
    min-height: 0;
}

/* Output / terminal panel */
.output-panel {
    flex: 1;
    display: flex;
    flex-direction: column;
    overflow: hidden;
    min-height: 0;
    border-right: 1px solid var(--border);
}

.output-panel .output {
    flex: 1;
    overflow-y: auto;
    padding: 12px 20px;
    font-size: 15px;
    line-height: 1.5;
    color: var(--green);
    white-space: pre-wrap;
    word-break: break-all;
}

/* Side panel (registers, stacks) */
.side-panel {
    width: 320px;
    flex-shrink: 0;
    overflow-y: auto;
    padding: 12px;
    display: flex;
    flex-direction: column;
    gap: 12px;
}

.panel-section {
    background: var(--surface);
    border: 1px solid var(--border);
    border-radius: 6px;
    padding: 10px;
}

.panel-section h3 {
    font-size: 12px;
    font-weight: 600;
    color: var(--accent);
    margin-bottom: 8px;
    text-transform: uppercase;
    letter-spacing: 0.5px;
}

/* Register display */
.registers {
    display: grid;
    grid-template-columns: auto 1fr;
    gap: 2px 12px;
    font-size: 13px;
}

.registers .reg-name {
    color: var(--dim);
}

.registers .reg-value {
    color: var(--text);
    text-align: right;
}

.registers .reg-value.changed {
    color: var(--yellow);
}

/* Stack display */
.stack-display {
    font-size: 13px;
}

.stack-display .stack-empty {
    color: var(--dim);
    font-style: italic;
}

.stack-display .stack-entry {
    display: flex;
    gap: 8px;
    padding: 1px 0;
}

.stack-display .stack-index {
    color: var(--dim);
    min-width: 24px;
    text-align: right;
}

.stack-display .stack-value {
    color: var(--text);
}

.stack-display .stack-tos {
    color: var(--accent);
    font-size: 11px;
}

/* Status bar */
.status-bar {
    display: flex;
    align-items: center;
    gap: 16px;
    padding: 4px 20px;
    font-size: 12px;
    color: var(--dim);
    border-top: 1px solid var(--border);
    flex-shrink: 0;
}

.status-bar .status-item {
    display: flex;
    align-items: center;
    gap: 4px;
}

.status-bar .status-label {
    color: var(--dim);
}

.status-bar .status-value {
    color: var(--text);
}

/* LED indicator */
.led {
    width: 10px;
    height: 10px;
    border-radius: 50%;
    background: #333;
    transition: background 0.15s, box-shadow 0.15s;
}

.led.on {
    background: var(--red);
    box-shadow: 0 0 6px var(--red);
}

/* Input bar */
.input-bar {
    display: flex;
    align-items: center;
    gap: 8px;
    padding: 8px 20px;
    border-top: 1px solid var(--border);
    flex-shrink: 0;
}

.input-bar .prompt {
    color: var(--accent);
    font-size: 15px;
}

.input-bar input {
    flex: 1;
    background: transparent;
    border: none;
    color: var(--text);
    font-family: var(--mono);
    font-size: 15px;
    outline: none;
}

/* Memory region bar */
.region-bar {
    display: flex;
    height: 16px;
    border-radius: 3px;
    overflow: hidden;
    font-size: 9px;
}

.region-bar .region {
    display: flex;
    align-items: center;
    justify-content: center;
    color: var(--bg);
    font-weight: 600;
    min-width: 2px;
}

.region-bar .region-kernel { background: #585b70; }
.region-bar .region-dict { background: var(--accent); }
.region-bar .region-free { background: #45475a; }
.region-bar .region-rstack { background: var(--orange); }
.region-bar .region-dstack { background: var(--green); }

/* Disassembly view */
.disasm-view {
    font-size: 12px;
    line-height: 1.6;
}

.disasm-line {
    display: flex;
    gap: 10px;
    padding: 1px 4px;
    border-radius: 2px;
}

.disasm-line.disasm-current {
    background: rgba(137, 180, 250, 0.15);
    color: var(--accent);
}

.disasm-addr {
    color: var(--dim);
    flex-shrink: 0;
}

.disasm-current .disasm-addr {
    color: var(--accent);
}

.disasm-instr {
    color: var(--text);
    white-space: pre;
}

.disasm-current .disasm-instr {
    color: var(--accent);
    font-weight: 600;
}

/* Disabled button styling */
.toolbar button:disabled {
    opacity: 0.4;
    cursor: not-allowed;
}

