  1→//! COR24 assembler
  2→//!
  3→//! Parses COR24 assembly language and produces machine code.
  4→//! Uses encoding tables extracted from the hardware decode ROM.
  5→
  6→use crate::cpu::encode;
  7→use crate::cpu::instruction::Opcode;
  8→use serde::{Deserialize, Serialize};
  9→use std::collections::HashMap;
 10→
 11→/// Assembly result
 12→#[derive(Debug, Clone, Serialize, Deserialize)]
 13→pub struct AssemblyResult {
 14→    pub bytes: Vec<u8>,
 15→    pub lines: Vec<AssembledLine>,
 16→    pub errors: Vec<String>,
 17→    pub labels: HashMap<String, u32>,
 18→}
 19→
 20→/// A single assembled line
 21→#[derive(Debug, Clone, Serialize, Deserialize)]
 22→pub struct AssembledLine {
 23→    pub address: u32,
 24→    pub bytes: Vec<u8>,
 25→    pub source: String,
 26→    pub label: Option<String>,
 27→}
 28→
 29→/// COR24 Assembler
 30→pub struct Assembler {
 31→    /// Current address
 32→    address: u32,
 33→    /// Symbol table
 34→    labels: HashMap<String, u32>,
 35→    /// Forward references to resolve
 36→    forward_refs: Vec<ForwardRef>,
 37→    /// Output bytes
 38→    output: Vec<u8>,
 39→    /// Assembled lines
 40→    lines: Vec<AssembledLine>,
 41→    /// Errors
 42→    errors: Vec<String>,
 43→}
 44→
 45→#[derive(Debug, Clone)]
 46→struct ForwardRef {
 47→    address: u32,
 48→    label: String,
 49→    ref_type: RefType,
 50→    line_num: usize,
 51→}
 52→
 53→#[derive(Debug, Clone, Copy)]
 54→enum RefType {
 55→    Absolute24, // la instruction
 56→    Relative8,  // branch instruction
 57→}
 58→
 59→impl Default for Assembler {
 60→    fn default() -> Self {
 61→        Self::new()
 62→    }
 63→}
 64→
 65→impl Assembler {
 66→    pub fn new() -> Self {
 67→        Self {
 68→            address: 0,
 69→            labels: HashMap::new(),
 70→            forward_refs: Vec::new(),
 71→            output: Vec::new(),
 72→            lines: Vec::new(),
 73→            errors: Vec::new(),
 74→        }
 75→    }
 76→
 77→    /// Assemble source code
 78→    pub fn assemble(&mut self, source: &str) -> AssemblyResult {
 79→        self.address = 0;
 80→        self.labels.clear();
 81→        self.forward_refs.clear();
 82→        self.output.clear();
 83→        self.lines.clear();
 84→        self.errors.clear();
 85→
 86→        // First pass: collect labels and emit code
 87→        for (line_num, line) in source.lines().enumerate() {
 88→            self.assemble_line(line, line_num);
 89→        }
 90→
 91→        // Second pass: resolve forward references
 92→        self.resolve_forward_refs();
 93→
 94→        // Update line bytes from resolved output
 95→        for line in &mut self.lines {
 96→            if !line.bytes.is_empty() {
 97→                let addr = line.address as usize;
 98→                let len = line.bytes.len();
 99→                if addr + len <= self.output.len() {
100→                    line.bytes = self.output[addr..addr + len].to_vec();
101→                }
102→            }
103→        }
104→
105→        AssemblyResult {
106→            bytes: self.output.clone(),
107→            lines: self.lines.clone(),
108→            errors: self.errors.clone(),
109→            labels: self.labels.clone(),
110→        }
111→    }
112→
113→    fn assemble_line(&mut self, line: &str, line_num: usize) {
114→        let line = line.trim();
115→
116→        // Skip empty lines and comments
117→        if line.is_empty() || line.starts_with(';') {
118→            return;
119→        }
120→
121→        // Strip trailing comments (semicolon only, matching reference as24)
122→        let line = if let Some(pos) = line.find(';') {
123→            line[..pos].trim()
124→        } else {
125→            line
126→        };
127→
128→        if line.is_empty() {
129→            return;
130→        }
131→
132→        let start_addr = self.address;
133→        let mut label = None;
134→        let mut instruction_part = line;
135→
136→        // Check for label (must be on its own line, matching reference as24)
137→        if let Some(colon_pos) = line.find(':') {
138→            let label_str = line[..colon_pos].trim();
139→            if !label_str.is_empty() {
140→                label = Some(label_str.to_string());
141→                self.labels.insert(label_str.to_string(), self.address);
142→            }
143→            instruction_part = line[colon_pos + 1..].trim();
144→            if !instruction_part.is_empty() {
145→                self.errors.push(format!(
146→                    "Line {}: label must be on its own line (as24 compatible)",
147→                    line_num + 1
148→                ));
149→                return;
150→            }

150→            }
151→        }
152→
153→        // Handle directives
154→        if instruction_part.starts_with('.') {
155→            let before_len = self.output.len();
156→            self.handle_directive(instruction_part, line_num);
157→            // Record directive bytes in lines so they appear in output
158→            let directive_bytes = self.output[before_len..].to_vec();
159→            if !directive_bytes.is_empty() || label.is_some() {
160→                self.lines.push(AssembledLine {
161→                    address: start_addr,
162→                    bytes: directive_bytes,
163→                    source: line.to_string(),
164→                    label,
165→                });
166→            }
167→            return;
168→        }
169→
170→        // Skip if no instruction
171→        if instruction_part.is_empty() {
172→            if label.is_some() {
173→                self.lines.push(AssembledLine {
174→                    address: start_addr,
175→                    bytes: vec![],
176→                    source: line.to_string(),
177→                    label,
178→                });
179→            }
180→            return;
181→        }
182→
183→        // Parse instruction
184→        let bytes = self.parse_instruction(instruction_part, line_num);
185→
186→        self.lines.push(AssembledLine {
187→            address: start_addr,
188→            bytes: bytes.clone(),
189→            source: line.to_string(),
190→            label,
191→        });
192→
193→        for b in bytes {
194→            self.output.push(b);
195→            self.address += 1;
196→        }
197→    }
198→
199→    fn handle_directive(&mut self, directive: &str, line_num: usize) {
200→        let parts: Vec<&str> = directive.split_whitespace().collect();
201→        if parts.is_empty() {
202→            return;
203→        }
204→
205→        match parts[0].to_lowercase().as_str() {
206→            ".org" => {
207→                if parts.len() > 1
208→                    && let Some(addr) = self.parse_number(parts[1])
209→                {
210→                    // Pad output to reach the new address
211→                    while self.output.len() < addr as usize {
212→                        self.output.push(0);
213→                    }
214→                    self.address = addr;
215→                }
216→            }
217→            ".byte" => {
218→                for part in &parts[1..] {
219→                    for token in part.split(',') {
220→                        let token = token.trim();
221→                        if token.is_empty() {
222→                            continue;
223→                        }
224→                        if let Some(val) = self.parse_number(token) {
225→                            self.output.push(val as u8);
226→                            self.address += 1;
227→                        }
228→                    }
229→                }
230→            }
231→            ".word" => {
232→                for part in &parts[1..] {
233→                    for token in part.split(',') {
234→                        let token = token.trim();
235→                        if token.is_empty() {
236→                            continue;
237→                        }
238→                        if let Some(val) = self.parse_number(token) {
239→                            // 24-bit word, little-endian
240→                            self.output.push((val & 0xFF) as u8);
241→                            self.output.push(((val >> 8) & 0xFF) as u8);
242→                            self.output.push(((val >> 16) & 0xFF) as u8);
243→                            self.address += 3;
244→                        } else if let Some(&addr) = self.labels.get(token) {
245→                            // Backward label reference
246→                            self.output.push((addr & 0xFF) as u8);
247→                            self.output.push(((addr >> 8) & 0xFF) as u8);
248→                            self.output.push(((addr >> 16) & 0xFF) as u8);
249→                            self.address += 3;
250→                        } else {
251→                            // Forward label reference — placeholder resolved in second pass
252→                            self.forward_refs.push(ForwardRef {
253→                                address: self.address,
254→                                label: token.to_string(),
255→                                ref_type: RefType::Absolute24,
256→                                line_num,
257→                            });
258→                            self.output.push(0x00);
259→                            self.output.push(0x00);
260→                            self.output.push(0x00);
261→                            self.address += 3;
262→                        }
263→                    }
264→                }
265→            }
266→            // .ascii and .asciz not supported by reference as24
267→            ".comm" => {
268→                // BSS allocation: .comm symbol, size
269→                // Defines label at current address and advances by size
270→                // No bytes emitted (memory is zero-initialized)
271→                if parts.len() >= 3 {
272→                    let sym = parts[1].trim_matches(',');
273→                    if let Some(size) = self.parse_number(parts[2].trim_matches(',')) {
274→                        self.labels.insert(sym.to_string(), self.address);
275→                        self.address += size;
276→                    }
277→                }
278→            }
279→            // Directives that are safe to ignore in flat memory model
280→            ".text" | ".data" | ".globl" | ".global" | ".section" | ".align" => {}
281→            _ => {}
282→        }
283→    }
284→
285→    fn parse_instruction(&mut self, inst: &str, line_num: usize) -> Vec<u8> {
286→        // Strip trailing comments
287→        let inst = if let Some(pos) = inst.find(';') {
288→            &inst[..pos]
289→        } else if let Some(pos) = inst.find('#') {
290→            &inst[..pos]
291→        } else {
292→            inst
293→        };
294→
295→        let parts: Vec<&str> = inst.split_whitespace().collect();
296→        if parts.is_empty() {
297→            return vec![];
298→        }
299→
300→        let mnemonic = parts[0].to_lowercase();
301→        let operands_str = if parts.len() > 1 {
302→            parts[1..].join(" ")
303→        } else {
304→            String::new()
305→        };
306→        let operands: Vec<&str> = if !operands_str.is_empty() {
307→            operands_str.split(',').map(|s| s.trim()).collect()
308→        } else {
309→            vec![]
310→        };
311→
312→        match mnemonic.as_str() {
313→            // Stack operations
314→            "push" => self.encode_push(&operands, line_num),
315→            "pop" => self.encode_pop(&operands, line_num),
316→
317→            // Move operations
318→            "mov" => self.encode_mov(&operands, line_num),
319→
320→            // Arithmetic
321→            "add" => self.encode_add(&operands, line_num),
322→            "sub" => self.encode_sub(&operands, line_num),
323→            "mul" => self.encode_mul(&operands, line_num),
324→
325→            // Logic
326→            "and" => self.encode_alu(&operands, Opcode::And, "and", line_num),
327→            "or" => self.encode_alu(&operands, Opcode::Or, "or", line_num),
328→            "xor" => self.encode_alu(&operands, Opcode::Xor, "xor", line_num),
329→
330→            // Shifts
331→            "shl" => self.encode_alu(&operands, Opcode::Shl, "shl", line_num),
332→            "sra" => self.encode_alu(&operands, Opcode::Sra, "sra", line_num),
333→            "srl" => self.encode_alu(&operands, Opcode::Srl, "srl", line_num),
334→
335→            // Compares
336→            "ceq" => self.encode_alu(&operands, Opcode::Ceq, "ceq", line_num),
337→            "cls" => self.encode_alu(&operands, Opcode::Cls, "cls", line_num),
338→            "clu" => self.encode_alu(&operands, Opcode::Clu, "clu", line_num),
339→
340→            // Branches
341→            "bra" => self.encode_branch(&operands, Opcode::Bra, line_num),
342→            "brf" => self.encode_branch(&operands, Opcode::Brf, line_num),
343→            "brt" => self.encode_branch(&operands, Opcode::Brt, line_num),
344→
345→            // Jumps
346→            "jmp" => self.encode_jmp(&operands, line_num),
347→            "jal" => self.encode_jal(&operands, line_num),
348→
349→            // Load operations
350→            "la" => self.encode_la(&operands, line_num),
351→            "lc" => self.encode_lc(&operands, false, line_num),
352→            "lcu" => self.encode_lc(&operands, true, line_num),
353→            "lb" => self.encode_load_store(&operands, Opcode::Lb, "lb", line_num),
354→            "lbu" => self.encode_load_store(&operands, Opcode::Lbu, "lbu", line_num),
355→            "lw" => self.encode_load_store(&operands, Opcode::Lw, "lw", line_num),
356→
357→            // Store operations
358→            "sb" => self.encode_load_store(&operands, Opcode::Sb, "sb", line_num),
359→            "sw" => self.encode_load_store(&operands, Opcode::Sw, "sw", line_num),
360→
361→            // Extensions
362→            "sxt" => self.encode_alu(&operands, Opcode::Sxt, "sxt", line_num),
363→            "zxt" => self.encode_alu(&operands, Opcode::Zxt, "zxt", line_num),
364→
365→            // Pseudo-instructions
366→            "nop" => vec![0xFF],
367→
368→            _ => {
369→                self.errors.push(format!(
370→                    "Line {}: Unknown instruction '{}'",
371→                    line_num + 1,
372→                    mnemonic
373→                ));
374→                vec![]
375→            }
376→        }
377→    }
