379→    fn parse_register(&self, s: &str) -> Option<u8> {
380→        let s = s.trim().to_lowercase();
381→        match s.as_str() {
382→            "r0" => Some(0),
383→            "r1" => Some(1),
384→            "r2" => Some(2),
385→            "fp" => Some(3),
386→            "sp" => Some(4),
387→            "z" | "c" => Some(5), // z=zero for comparisons, c=condition flag for mov
388→            "iv" => Some(6),
389→            "ir" => Some(7),
390→            _ => None,
391→        }
392→    }
