358→impl CpuState {
359→    /// Create a new CPU state with default values
360→    pub fn new() -> Self {
361→        let mut state = Self {
362→            pc: RESET_ADDRESS,
363→            registers: [0; 8],
364→            c: false,
365→            memory: vec![0; SRAM_SIZE],
366→            ebr: vec![0; EBR_SIZE],
367→            halted: false,
368→            intis: false,
369→            cycles: 0,
370→            instructions: 0,
371→            io: IoState::new(),
372→            trace: TraceBuffer::default(),
