403→    }
404→
405→    /// Check if address is in EBR region (0xFEE000-0xFEFFFF)
406→    fn is_ebr_addr(addr: u32) -> bool {
407→        addr >= EBR_BASE && addr < EBR_BASE + EBR_SIZE as u32
408→    }
409→
410→    /// Read a byte from memory or I/O
411→    pub fn read_byte(&self, addr: u32) -> u8 {
412→        let addr = addr & 0xFFFFFF; // Mask to 24 bits
413→
414→        if Self::is_io_addr(addr) {
415→            self.read_io(addr)
416→        } else if Self::is_ebr_addr(addr) {
417→            self.ebr[(addr - EBR_BASE) as usize]
418→        } else if (addr as usize) < SRAM_SIZE {
419→            self.memory[addr as usize]
420→        } else {
421→            0 // Unmapped region
422→        }
423→    }
424→
425→    /// Write a byte to memory or I/O
426→    pub fn write_byte(&mut self, addr: u32, value: u8) {
427→        let addr = addr & 0xFFFFFF; // Mask to 24 bits
428→
429→        if Self::is_io_addr(addr) {
430→            self.write_io(addr, value);
431→        } else if Self::is_ebr_addr(addr) {
432→            self.ebr[(addr - EBR_BASE) as usize] = value;
433→        } else if (addr as usize) < SRAM_SIZE {
434→            self.memory[addr as usize] = value;
435→        }
436→        // Writes to unmapped regions are silently ignored
437→    }
438→
439→    /// Read from I/O register
440→    fn read_io(&self, addr: u32) -> u8 {
441→        match addr {
442→            IO_LEDSWDAT => self.io.switches,
443→            IO_INTENABLE => self.io.int_enable,
444→            IO_UARTDATA => self.io.uart_rx,
445→            IO_UARTSTAT => {
446→                let mut status = 0u8;
447→                if self.io.uart_rx_ready {
448→                    status |= 0x01; // Bit 0: RX data ready
449→                }
450→                // Bit 1: CTS active (always asserted in emulation)
451→                status |= 0x02;
452→                if self.io.uart_rx_overflow {
453→                    status |= 0x04; // Bit 2: RX overflow
454→                }
455→                if self.io.uart_tx_busy {
456→                    status |= 0x80; // Bit 7: TX busy
457→                }
458→                status
459→            }
460→            _ => 0, // Unknown I/O address
461→        }
462→    }
463→
464→    /// Read from I/O with side effects (auto-acknowledge)
465→    /// This is the version that should be called during execution.
466→    pub fn read_byte_exec(&mut self, addr: u32) -> u8 {
467→        let addr = addr & 0xFFFFFF;
468→        if addr == IO_UARTDATA {
469→            let data = self.io.uart_rx;
470→            self.io.uart_rx_ready = false; // Auto-acknowledge: reading data clears ready
471→            data
472→        } else {
473→            self.read_byte(addr)
474→        }
475→    }
476→
477→    /// Write to I/O register
478→    fn write_io(&mut self, addr: u32, value: u8) {
479→        match addr {
480→            IO_LEDSWDAT => {
481→                self.io.leds = value;
482→            }
483→            IO_INTENABLE => {
484→                self.io.int_enable = value;
485→            }
486→            IO_UARTDATA => {
487→                if self.io.uart_tx_busy {
488→                    // Write while busy — character dropped (hardware would ignore)
489→                    self.io.uart_tx_dropped += 1;
490→                } else {
491→                    self.io.uart_tx = value;
492→                    if value != 0 {
493→                        self.io.uart_output.push(value as char);
494→                    }
495→                    // TX busy for N cycles (simulates transmission time)
496→                    if self.io.uart_tx_busy_cycles > 0 {
497→                        self.io.uart_tx_busy = true;
498→                        self.io.uart_tx_countdown = self.io.uart_tx_busy_cycles;
499→                    }

500→                    // cycles=0 means instant ready (legacy/test mode)
501→                }
502→            }
503→            IO_UARTSTAT => {
504→                // Writing to status can clear overflow flag
505→                if value & 0x04 != 0 {
506→                    self.io.uart_rx_overflow = false;
507→                }
508→            }
509→            _ => {} // Ignore unknown I/O address
510→        }
511→    }
512→
513→    /// Tick UART timers — call after each instruction execution
514→    pub fn uart_tick(&mut self) {
515→        if self.io.uart_never_ready {
516→            // TX stays busy forever — tests that programs poll before writing
517→            return;
518→        }
519→        if self.io.uart_tx_countdown > 0 {
520→            self.io.uart_tx_countdown -= 1;
521→            if self.io.uart_tx_countdown == 0 {
522→                self.io.uart_tx_busy = false;
523→            }
524→        }
525→    }
526→
527→    /// Send a character to UART RX (simulates external input)
528→    pub fn uart_send_rx(&mut self, ch: u8) {
529→        if self.io.uart_rx_ready {
530→            self.io.uart_rx_overflow = true; // Previous data not read
531→        }
532→        self.io.uart_rx = ch;
533→        self.io.uart_rx_ready = true;
534→    }
535→
536→    /// Read a 24-bit word from memory (little-endian)
537→    pub fn read_word(&self, addr: u32) -> u32 {
538→        let b0 = self.read_byte(addr) as u32;
539→        let b1 = self.read_byte(addr.wrapping_add(1)) as u32;
540→        let b2 = self.read_byte(addr.wrapping_add(2)) as u32;
541→        b0 | (b1 << 8) | (b2 << 16)
542→    }
543→
544→    /// Write a 24-bit word to memory (little-endian)
545→    pub fn write_word(&mut self, addr: u32, value: u32) {
546→        self.write_byte(addr, (value & 0xFF) as u8);
547→        self.write_byte(addr.wrapping_add(1), ((value >> 8) & 0xFF) as u8);
548→        self.write_byte(addr.wrapping_add(2), ((value >> 16) & 0xFF) as u8);
549→    }
550→
551→    /// Get register value (masked to 24 bits)
552→    pub fn get_reg(&self, reg: u8) -> u32 {
553→        self.registers[(reg & 0x07) as usize] & 0xFFFFFF
554→    }
555→
556→    /// Set register value (masked to 24 bits)
557→    pub fn set_reg(&mut self, reg: u8, value: u32) {
558→        self.registers[(reg & 0x07) as usize] = value & 0xFFFFFF;
559→    }
560→
561→    /// Sign extend 8-bit to 24-bit
562→    pub fn sign_extend_8(value: u8) -> u32 {
563→        if value & 0x80 != 0 {
564→            0xFFFF00 | (value as u32)
565→        } else {
566→            value as u32
567→        }
568→    }
569→
570→    /// Check if an interrupt should fire
571→    /// Hardware: ireq = uart_rxrdy && ienab; irqis = ireq && !intis
572→    pub fn interrupt_pending(&self) -> bool {
573→        self.io.uart_rx_ready && (self.io.int_enable & 0x01 != 0) && !self.intis
574→    }
575→
576→    /// Mask to 24 bits
577→    pub fn mask_24(value: u32) -> u32 {
578→        value & 0xFFFFFF
579→    }
580→
581→    /// Load program into memory at given address
582→    pub fn load_program(&mut self, start_addr: u32, data: &[u8]) {
583→        for (i, &byte) in data.iter().enumerate() {
584→            self.write_byte(start_addr + i as u32, byte);
585→        }
586→    }
587→}
588→
589→/// Instruction decode ROM
590→/// Maps 8-bit instruction bytes to 12-bit decoded values: [opcode(5):ra(3):rb(3)]
591→/// Uses the const DECODE_ROM extracted from dis_rom.v
592→#[derive(Clone)]
593→pub struct DecodeRom;
594→
595→impl Default for DecodeRom {
596→    fn default() -> Self {
597→        Self::new()
598→    }
599→}
600→
601→impl DecodeRom {
602→    /// Create decode ROM (uses static const array)
603→    pub fn new() -> Self {
604→        Self
605→    }
606→
607→    /// Decode an instruction byte
608→    pub fn decode(&self, byte: u8) -> u16 {
609→        crate::cpu::decode_rom::DECODE_ROM[byte as usize]
610→    }
611→
612→    /// Check if an instruction byte is valid
613→    pub fn is_valid(&self, byte: u8) -> bool {
614→        crate::cpu::decode_rom::DECODE_ROM[byte as usize] != 0xFFF
615→    }
616→}
