//! Forth debugger component — COR24 emulator with Forth-aware inspection.

use crate::config::{ForthTier, StackSize};
use cor24_emulator::{Assembler, EmulatorCore};
use gloo::timers::callback::Timeout;
use std::collections::VecDeque;
use web_sys::{HtmlElement, HtmlInputElement};
use yew::prelude::*;

/// Execution batch size per tick (instructions).
const BATCH_SIZE: u64 = 50_000;

/// Tick interval in milliseconds.
const TICK_MS: u32 = 25;

pub enum Msg {
    /// Load and start the emulator.
    Init,
    /// Run a batch of instructions.
    Tick,
    /// User typed in the input bar.
    InputChanged(String),
    /// User pressed Enter to send input.
    SendInput,
    /// Switch Forth tier.
    SetTier(ForthTier),
    /// Switch stack size.
    SetStack(StackSize),
    /// Reset emulator.
    Reset,
    /// Step one instruction.
    Step,
    /// Step over (run until return from call).
    StepOver,
    /// Toggle run/pause.
    PauseResume,
    /// Handle keydown in input field.
    InputKeyDown(KeyboardEvent),
}

pub struct Debugger {
    emulator: EmulatorCore,
    tier: ForthTier,
    stack_size: StackSize,
    output: String,
    input: String,
    running: bool,
    halted: bool,
    /// Pending timeout handle (kept alive to prevent cancel).
    _tick_handle: Option<Timeout>,
    /// Previous register values for change highlighting.
    prev_regs: [u32; 8],
    prev_pc: u32,
    /// Pending UART RX bytes to feed one-at-a-time.
    uart_rx_queue: VecDeque<u8>,
    /// Ref to output div for auto-scroll.
    output_ref: NodeRef,
}

impl Debugger {
    fn load_binary(&mut self, _ctx: &Context<Self>) {
        let mut asm = Assembler::new();
        let result = asm.assemble(self.tier.assembly());

        if !result.errors.is_empty() {
            self.output = "Assembly errors:\n".to_string();
            for e in &result.errors {
                self.output.push_str(e);
                self.output.push('\n');
            }
            return;
        }

        self.emulator.hard_reset();
        self.emulator.load_program(0, &result.bytes);
        self.emulator.load_program_extent(result.bytes.len() as u32);
        self.emulator.set_pc(0);
        self.output.clear();
        self.halted = false;
        self.prev_regs = [0; 8];
        self.prev_pc = 0;
        self.uart_rx_queue.clear();

        // Start paused — debugger mode.
        self.running = false;
        self.emulator.pause();
    }

    fn schedule_tick(&mut self, ctx: &Context<Self>) {
        let link = ctx.link().clone();
        self._tick_handle = Some(Timeout::new(TICK_MS, move || {
            link.send_message(Msg::Tick);
        }));
    }

    fn snapshot_regs(&self) -> [u32; 8] {
        let snap = self.emulator.snapshot();
        snap.regs
    }

    fn read_data_stack(&self) -> Vec<u32> {
        let sp = self.emulator.snapshot().regs[4]; // sp = r4
        let stack_top = self.stack_size.initial_sp();
        let mut cells = Vec::new();
        let mut addr = stack_top;
        // Stack grows downward; entries are from stack_top-3 down to sp.
        while addr > sp && cells.len() < 64 {
            addr -= 3; // cell = 3 bytes
            let val = self.emulator.read_word(addr);
            cells.push(val & 0xFFFFFF);
        }
        cells.reverse(); // bottom of stack first
        cells
    }

    fn read_return_stack(&self) -> Vec<u32> {
        let rsp = self.emulator.snapshot().regs[1]; // r1 = RSP
        let rstack_base: u32 = 0x0F0000;
        let mut cells = Vec::new();
        let mut addr = rstack_base;
        while addr > rsp && cells.len() < 64 {
            addr -= 3;
            let val = self.emulator.read_word(addr);
            cells.push(val & 0xFFFFFF);
        }
        cells.reverse();
        cells
    }

    /// Disassemble instructions around the current PC.
    fn disassemble_around_pc(
        &self,
        count_before: usize,
        count_after: usize,
    ) -> Vec<(u32, String, bool)> {
        let pc = self.emulator.snapshot().pc;
        // Disassemble forward from PC to get the current + after
        let forward = self.emulator.disassemble(pc, count_after + 1);

        // For instructions before PC, scan backwards heuristically.
        // COR24 has variable-length instructions (1, 2, or 4 bytes).
        // Walk backwards by trying offsets.
        let mut before = Vec::new();
        if count_before > 0 && pc > 0 {
            // Collect candidate addresses by scanning backwards
            let scan_start = pc.saturating_sub((count_before as u32) * 4 + 8);
            let all = self.emulator.disassemble(scan_start, 128);
            // Find instructions that end at or before PC
            for &(addr, ref mnemonic, size) in &all {
                if addr < pc {
                    before.push((addr, mnemonic.clone(), size));
                } else {
                    break;
                }
            }
            // Take only the last count_before
            let skip = before.len().saturating_sub(count_before);
            before = before.into_iter().skip(skip).collect();
        }

        let mut result: Vec<(u32, String, bool)> = Vec::new();
        for (addr, mnemonic, _size) in before {
            result.push((addr, mnemonic, false));
        }
        for (addr, mnemonic, _size) in forward {
            result.push((addr, mnemonic, addr == pc));
        }
        result
    }

    /// Feed one byte from the UART RX queue if the UART is ready.
    fn feed_uart_byte(&mut self) {
        if self.uart_rx_queue.is_empty() {
            return;
        }
        // Check if UART RX buffer can accept (status register bit 0)
        let status = self.emulator.read_byte(0xFF0101);
        if status & 0x01 == 0 {
            // UART ready to receive — feed one byte
            if let Some(byte) = self.uart_rx_queue.pop_front() {
                self.emulator.send_uart_byte(byte);
            }
        }
    }

    /// Collect UART output and auto-scroll.
    fn collect_uart_output(&mut self) {
        let uart = self.emulator.get_uart_output();
        if !uart.is_empty() {
            self.output.push_str(uart);
            self.emulator.clear_uart_output();
        }
    }

    fn auto_scroll(&self) {
        if let Some(el) = self.output_ref.cast::<HtmlElement>() {
            el.set_scroll_top(el.scroll_height());
        }
    }
}

impl Component for Debugger {
    type Message = Msg;
    type Properties = ();

    fn create(ctx: &Context<Self>) -> Self {
        ctx.link().send_message(Msg::Init);
        Self {
            emulator: EmulatorCore::new(),
            tier: ForthTier::Bootstrap,
            stack_size: StackSize::ThreeKb,
            output: String::new(),
            input: String::new(),
            running: false,
            halted: false,
            _tick_handle: None,
            prev_regs: [0; 8],
            prev_pc: 0,
            uart_rx_queue: VecDeque::new(),
            output_ref: NodeRef::default(),
        }
    }

    fn update(&mut self, ctx: &Context<Self>, msg: Self::Message) -> bool {
        match msg {
            Msg::Init => {
                self.load_binary(ctx);
                true
            }

            Msg::Tick => {
                if !self.running {
                    return false;
                }

                // Save previous state for change highlighting.
                self.prev_regs = self.snapshot_regs();
                self.prev_pc = self.emulator.snapshot().pc;

                // Feed pending UART input bytes (poll-before-feed).
                self.feed_uart_byte();

                let _result = self.emulator.run_batch(BATCH_SIZE);

                // Collect UART output.
                self.collect_uart_output();

                if self.emulator.is_halted() {
                    self.running = false;
                    self.halted = true;
                } else if self.running {
                    self.schedule_tick(ctx);
                }

                true
            }

            Msg::InputChanged(val) => {
                self.input = val;
                false
            }

            Msg::SendInput => {
                if self.input.is_empty() {
                    return false;
                }
                // Queue bytes for poll-before-feed delivery.
                for b in self.input.bytes() {
                    self.uart_rx_queue.push_back(b);
                }
                self.uart_rx_queue.push_back(b'\n');
                self.input.clear();

                if !self.running && !self.halted {
                    self.running = true;
                    self.emulator.resume();
                    self.schedule_tick(ctx);
                }
                true
            }

            Msg::SetTier(tier) => {
                self.tier = tier;
                self.load_binary(ctx);
                true
            }

            Msg::SetStack(size) => {
                self.stack_size = size;
                self.load_binary(ctx);
                true
            }

            Msg::Reset => {
                self.load_binary(ctx);
                true
            }

            Msg::Step => {
                if self.halted {
                    return false;
                }
                self.running = false;
                self.emulator.resume();

                self.prev_regs = self.snapshot_regs();
                self.prev_pc = self.emulator.snapshot().pc;

                self.feed_uart_byte();
                let _result = self.emulator.step();
                self.collect_uart_output();

                self.emulator.pause();
                if self.emulator.is_halted() {
                    self.halted = true;
                }
                true
            }

            Msg::StepOver => {
                if self.halted {
                    return false;
                }
                self.running = false;
                self.emulator.resume();

                self.prev_regs = self.snapshot_regs();
                self.prev_pc = self.emulator.snapshot().pc;

                self.feed_uart_byte();
                let _result = self.emulator.step_over();
                self.collect_uart_output();

                self.emulator.pause();
                if self.emulator.is_halted() {
                    self.halted = true;
                }
                true
            }

            Msg::PauseResume => {
                if self.halted {
                    return false;
                }
                if self.running {
                    self.running = false;
                    self.emulator.pause();
                    self._tick_handle = None;
                } else {
                    self.running = true;
                    self.emulator.resume();
                    self.schedule_tick(ctx);
                }
                true
            }

            Msg::InputKeyDown(e) => {
                if e.key() == "Enter" {
                    ctx.link().send_message(Msg::SendInput);
                }
                false
            }
        }
    }

    fn rendered(&mut self, _ctx: &Context<Self>, _first_render: bool) {
        self.auto_scroll();
    }

    fn view(&self, ctx: &Context<Self>) -> Html {
        let snap = self.emulator.snapshot();
        let data_stack = self.read_data_stack();
        let return_stack = self.read_return_stack();
        let disasm = self.disassemble_around_pc(4, 8);

        let reg_names = [
            "r0/W", "r1/RSP", "r2/IP", "r3/fp", "sp/DSP", "r5/zc", "r6/iv", "r7/ir",
        ];

        html! {
            <div class="debugger">
                // Toolbar
                <div class="toolbar">
                    <button onclick={ctx.link().callback(|_| Msg::PauseResume)}
                            class={if self.running { "active" } else { "" }}>
                        { if self.running { "Pause" } else { "Run" } }
                    </button>
                    <button onclick={ctx.link().callback(|_| Msg::Step)}
                            disabled={self.running || self.halted}>
                        {"Step"}
                    </button>
                    <button onclick={ctx.link().callback(|_| Msg::StepOver)}
                            disabled={self.running || self.halted}>
                        {"Step Over"}
                    </button>
                    <button onclick={ctx.link().callback(|_| Msg::Reset)}>
                        {"Reset"}
                    </button>

                    <select onchange={ctx.link().callback(|e: Event| {
                        let select: HtmlInputElement = e.target_unchecked_into();
                        let tier = match select.value().as_str() {
                            "Bootstrap" => ForthTier::Bootstrap,
                            _ => ForthTier::Bootstrap,
                        };
                        Msg::SetTier(tier)
                    })}>
                        { for ForthTier::ALL.iter().map(|t| {
                            html! {
                                <option value={t.label()} selected={*t == self.tier}>
                                    { t.label() }
                                </option>
                            }
                        })}
                    </select>

                    <select onchange={ctx.link().callback(|e: Event| {
                        let select: HtmlInputElement = e.target_unchecked_into();
                        let size = match select.value().as_str() {
                            "3 KB" => StackSize::ThreeKb,
                            _ => StackSize::EightKb,
                        };
                        Msg::SetStack(size)
                    })}>
                        { for StackSize::ALL.iter().map(|s| {
                            html! {
                                <option value={s.label()} selected={*s == self.stack_size}>
                                    { s.label() }
                                </option>
                            }
                        })}
                    </select>

                    <span class="tier-desc">{ self.tier.description() }</span>
                </div>

                // Main panels
                <div class="panels">
                    // Output / terminal
                    <div class="output-panel">
                        <div class="output" ref={self.output_ref.clone()}>{ &self.output }</div>
                        <div class="input-bar">
                            <span class="prompt">{"> "}</span>
                            <input
                                type="text"
                                value={self.input.clone()}
                                oninput={ctx.link().callback(|e: InputEvent| {
                                    let input: HtmlInputElement = e.target_unchecked_into();
                                    Msg::InputChanged(input.value())
                                })}
                                onkeydown={ctx.link().callback(Msg::InputKeyDown)}
                                placeholder="Type Forth input..."
                            />
                        </div>
                    </div>

                    // Side panel: registers + stacks
                    <div class="side-panel">
                        // CPU Registers
                        <div class="panel-section">
                            <h3>{"Registers"}</h3>
                            <div class="registers">
                                <span class="reg-name">{"PC"}</span>
                                <span class={classes!(
                                    "reg-value",
                                    (snap.pc != self.prev_pc).then_some("changed")
                                )}>
                                    { format!("{:06X}", snap.pc) }
                                </span>
                                { for (0..8).map(|i| {
                                    let changed = snap.regs[i] != self.prev_regs[i];
                                    html! {
                                        <>
                                            <span class="reg-name">{ reg_names[i] }</span>
                                            <span class={classes!(
                                                "reg-value",
                                                changed.then_some("changed")
                                            )}>
                                                { format!("{:06X}", snap.regs[i] & 0xFFFFFF) }
                                            </span>
                                        </>
                                    }
                                })}
                                <span class="reg-name">{"C"}</span>
                                <span class="reg-value">
                                    { if snap.c { "1" } else { "0" } }
                                </span>
                            </div>
                        </div>

                        // Data Stack
                        <div class="panel-section">
                            <h3>{ format!("Data Stack ({})", data_stack.len()) }</h3>
                            <div class="stack-display">
                                { if data_stack.is_empty() {
                                    html! { <span class="stack-empty">{"(empty)"}</span> }
                                } else {
                                    html! {
                                        { for data_stack.iter().enumerate().map(|(i, val)| {
                                            let is_tos = i == data_stack.len() - 1;
                                            html! {
                                                <div class="stack-entry">
                                                    <span class="stack-index">
                                                        { format!("[{}]", i) }
                                                    </span>
                                                    <span class="stack-value">
                                                        { format!("{:06X}  {}", val, val) }
                                                    </span>
                                                    { if is_tos {
                                                        html! { <span class="stack-tos">{"<- TOS"}</span> }
                                                    } else {
                                                        html! {}
                                                    }}
                                                </div>
                                            }
                                        })}
                                    }
                                }}
                            </div>
                        </div>

                        // Return Stack
                        <div class="panel-section">
                            <h3>{ format!("Return Stack ({})", return_stack.len()) }</h3>
                            <div class="stack-display">
                                { if return_stack.is_empty() {
                                    html! { <span class="stack-empty">{"(empty)"}</span> }
                                } else {
                                    html! {
                                        { for return_stack.iter().enumerate().map(|(i, val)| {
                                            let is_top = i == return_stack.len() - 1;
                                            html! {
                                                <div class="stack-entry">
                                                    <span class="stack-index">
                                                        { format!("[{}]", i) }
                                                    </span>
                                                    <span class="stack-value">
                                                        { format!("{:06X}  {}", val, val) }
                                                    </span>
                                                    { if is_top {
                                                        html! { <span class="stack-tos">{"<- TOP"}</span> }
                                                    } else {
                                                        html! {}
                                                    }}
                                                </div>
                                            }
                                        })}
                                    }
                                }}
                            </div>
                        </div>

                        // LED + status
                        <div class="panel-section">
                            <h3>{"Hardware"}</h3>
                            <div class="registers">
                                <span class="reg-name">{"LED"}</span>
                                <span class="reg-value">
                                    <span class={classes!(
                                        "led",
                                        (snap.led != 0).then_some("on")
                                    )}></span>
                                </span>
                                <span class="reg-name">{"Cycles"}</span>
                                <span class="reg-value">{ format!("{}", snap.cycles) }</span>
                                <span class="reg-name">{"Instrs"}</span>
                                <span class="reg-value">{ format!("{}", snap.instructions) }</span>
                            </div>
                        </div>

                        // Disassembly
                        <div class="panel-section">
                            <h3>{"Disassembly"}</h3>
                            <div class="disasm-view">
                                { for disasm.iter().map(|(addr, mnemonic, is_current)| {
                                    html! {
                                        <div class={classes!(
                                            "disasm-line",
                                            is_current.then_some("disasm-current")
                                        )}>
                                            <span class="disasm-addr">
                                                { format!("{:06X}", addr) }
                                            </span>
                                            <span class="disasm-instr">
                                                { mnemonic }
                                            </span>
                                        </div>
                                    }
                                })}
                            </div>
                        </div>
                    </div>
                </div>

                // Status bar
                <div class="status-bar">
                    <div class="status-item">
                        <span class="status-label">{"Status:"}</span>
                        <span class="status-value">
                            { if self.halted { "Halted" }
                              else if self.running { "Running" }
                              else { "Paused" }
                            }
                        </span>
                    </div>
                    <div class="status-item">
                        <span class="status-label">{"PC:"}</span>
                        <span class="status-value">{ format!("0x{:06X}", snap.pc) }</span>
                    </div>
                    <div class="status-item">
                        <span class="status-label">{"Tier:"}</span>
                        <span class="status-value">{ self.tier.label() }</span>
                    </div>
                    <div class="status-item">
                        <span class="status-label">{"Stack:"}</span>
                        <span class="status-value">{ self.stack_size.label() }</span>
                    </div>
                </div>
            </div>
        }
    }
}

input.content:
/* Debugger layout */
.debugger {
    flex: 1;
    display: flex;
    flex-direction: column;
    overflow: hidden;
    min-height: 0;
}

/* Toolbar */
.toolbar {
    display: flex;
    align-items: center;
    gap: 8px;
    padding: 8px 20px;
    border-bottom: 1px solid var(--border);
    flex-shrink: 0;
    flex-wrap: wrap;
}

.toolbar button {
    background: var(--surface);
    color: var(--text);
    border: 1px solid var(--border);
    border-radius: 4px;
    padding: 4px 12px;
    font-family: var(--mono);
    font-size: 13px;
    cursor: pointer;
    transition: background 0.15s;
}

.toolbar button:hover {
    background: var(--border);
}

.toolbar button.active {
    background: var(--accent);
    color: var(--bg);
    border-color: var(--accent);
}

.toolbar select {
    background: var(--surface);
    color: var(--text);
    border: 1px solid var(--border);
    border-radius: 4px;
    padding: 4px 8px;
    font-family: var(--mono);
    font-size: 13px;
}

.toolbar .tier-desc {
    font-size: 12px;
    color: var(--dim);
    margin-left: 4px;
}

/* Memory map */
.memory-map {
    display: flex;
    align-items: center;
    gap: 8px;
    padding: 4px 20px;
    border-bottom: 1px solid var(--border);
    flex-shrink: 0;
}

.memory-map-label {
    font-size: 10px;
    color: var(--dim);
    text-transform: uppercase;
    letter-spacing: 0.5px;
    flex-shrink: 0;
}

/* Main panels */
.panels {
    flex: 1;
    display: flex;
    overflow: hidden;
    min-height: 0;
}

/* Output / terminal panel */
.output-panel {
    flex: 1;
    display: flex;
    flex-direction: column;
    overflow: hidden;
    min-height: 0;
    border-right: 1px solid var(--border);
}

.output-panel .output {
    flex: 1;
    overflow-y: auto;
    padding: 12px 20px;
    font-size: 15px;
    line-height: 1.5;
    color: var(--green);
    white-space: pre-wrap;
    word-break: break-all;
}

/* Side panel (registers, stacks) */
.side-panel {
    width: 380px;
    flex-shrink: 0;
    overflow-y: auto;
    padding: 12px;
    display: flex;
    flex-direction: column;
    gap: 12px;
}

.panel-section {
    background: var(--surface);
    border: 1px solid var(--border);
    border-radius: 6px;
    padding: 10px;
}

.panel-section h3 {
    font-size: 12px;
    font-weight: 600;
    color: var(--accent);
    margin-bottom: 8px;
    text-transform: uppercase;
    letter-spacing: 0.5px;
}

/* Register display */
.registers {
    display: grid;
    grid-template-columns: auto 1fr;
    gap: 2px 12px;
    font-size: 13px;
}

.registers .reg-name {
    color: var(--dim);
}

.registers .reg-value {
    color: var(--text);
    text-align: right;
}

.registers .reg-value.changed {
    color: var(--yellow);
}

/* Stack display */
.stack-display {
    font-size: 13px;
}

.stack-display .stack-empty {
    color: var(--dim);
    font-style: italic;
}

.stack-display .stack-entry {
    display: flex;
    gap: 8px;
    padding: 1px 0;
}

.stack-display .stack-index {
    color: var(--dim);
    min-width: 24px;
    text-align: right;
}

.stack-display .stack-value {
    color: var(--text);
}

.stack-display .stack-tos {
    color: var(--accent);
    font-size: 11px;
}

/* Caller chain */
.caller-chain {
    font-size: 12px;
}

.caller-entry {
    display: flex;
    gap: 8px;
    padding: 1px 0;
}

.caller-depth {
    color: var(--dim);
    min-width: 16px;
}

.caller-name {
    color: var(--accent);
    flex: 1;
}

.caller-addr {
    color: var(--dim);
    font-size: 11px;
}

/* Status bar */
.status-bar {
    display: flex;
    align-items: center;
    gap: 16px;
    padding: 4px 20px;
    font-size: 12px;
    color: var(--dim);
    border-top: 1px solid var(--border);
    flex-shrink: 0;
}

.status-bar .status-item {
    display: flex;
    align-items: center;
    gap: 4px;
}

.status-bar .status-label {
    color: var(--dim);
}

.status-bar .status-value {
    color: var(--text);
}

/* LED indicator */
.led {
    width: 10px;
    height: 10px;
    border-radius: 50%;
    background: #333;
    transition: background 0.15s, box-shadow 0.15s;
}

.led.on {
    background: var(--red);
    box-shadow: 0 0 6px var(--red);
}

/* Input bar */
.input-bar {
    display: flex;
    align-items: center;
    gap: 8px;
    padding: 8px 20px;
    border-top: 1px solid var(--border);
    flex-shrink: 0;
}

.input-bar .prompt {
    color: var(--accent);
    font-size: 15px;
}

.input-bar input {
    flex: 1;
    background: transparent;
    border: none;
    color: var(--text);
    font-family: var(--mono);
    font-size: 15px;
    outline: none;
}

/* Memory region bar */
.region-bar {
    display: flex;
    height: 16px;
    border-radius: 3px;
    overflow: hidden;
    font-size: 9px;
    flex: 1;
}

.region-bar .region {
    display: flex;
    align-items: center;
    justify-content: center;
    color: var(--bg);
    font-weight: 600;
    min-width: 2px;
    transition: width 0.3s;
}

.region-bar .region-kernel { background: #585b70; }
.region-bar .region-dict { background: var(--accent); }
.region-bar .region-free { background: #45475a; }
.region-bar .region-rstack { background: var(--orange); }
.region-bar .region-dstack { background: var(--green); }

/* Disassembly view */
.disasm-view {
    font-size: 12px;
    line-height: 1.6;
}

.disasm-label {
    color: var(--accent);
    font-size: 11px;
    font-weight: 600;
    padding: 2px 4px 0;
    opacity: 0.7;
}

.disasm-line {
    display: flex;
    gap: 6px;
    padding: 1px 4px;
    border-radius: 2px;
    cursor: pointer;
    user-select: none;
}

.disasm-line:hover {
    background: rgba(255, 255, 255, 0.04);
}

.disasm-line.disasm-current {
    background: rgba(137, 180, 250, 0.15);
    color: var(--accent);
}

.disasm-line.disasm-breakpoint .disasm-bp-gutter {
    color: var(--red);
}

.disasm-bp-gutter {
    width: 10px;
    flex-shrink: 0;
    text-align: center;
    color: transparent;
    font-size: 10px;
    line-height: 1.6;
}

.disasm-line:hover .disasm-bp-gutter {
    color: var(--dim);
}

.disasm-line.disasm-breakpoint .disasm-bp-gutter {
    color: var(--red);
}

.disasm-addr {
    color: var(--dim);
    flex-shrink: 0;
}

.disasm-current .disasm-addr {
    color: var(--accent);
}

.disasm-instr {
    color: var(--text);
    white-space: pre;
}

.disasm-current .disasm-instr {
    color: var(--accent);
    font-weight: 600;
}

/* Disabled button styling */
.toolbar button:disabled {
    opacity: 0.4;
    cursor: not-allowed;
}

/* Bottom tab panel */
.bottom-tabs {
    padding: 0;
}

.tab-bar {
    display: flex;
    border-bottom: 1px solid var(--border);
}

.tab-btn {
    background: transparent;
    color: var(--dim);
    border: none;
    padding: 6px 14px;
    font-family: var(--mono);
    font-size: 11px;
    cursor: pointer;
    text-transform: uppercase;
    letter-spacing: 0.5px;
    border-bottom: 2px solid transparent;
    transition: color 0.15s, border-color 0.15s;
}

.tab-btn:hover {
    color: var(--text);
}

.tab-btn.active {
    color: var(--accent);
    border-bottom-color: var(--accent);
}

/* Dictionary panel */
.dict-panel {
    padding: 8px;
}

.dict-list {
    max-height: 200px;
    overflow-y: auto;
}

.dict-entry {
    display: flex;
    gap: 8px;
    padding: 2px 4px;
    border-radius: 2px;
    cursor: pointer;
    font-size: 12px;
    align-items: center;
}

.dict-entry:hover {
    background: rgba(255, 255, 255, 0.04);
}

.dict-entry.dict-selected {
    background: rgba(137, 180, 250, 0.15);
}

.dict-addr {
    color: var(--dim);
    font-size: 11px;
    flex-shrink: 0;
}

.dict-name {
    color: var(--text);
    flex: 1;
}

.dict-kind {
    font-size: 10px;
    padding: 0 4px;
    border-radius: 2px;
    flex-shrink: 0;
}

.dict-primitive .dict-kind {
    color: var(--green);
}

.dict-colon .dict-kind {
    color: var(--accent);
}

.dict-thread .dict-kind {
    color: var(--orange);
}

/* Word inspector */
.word-inspector {
    margin-top: 8px;
    padding-top: 8px;
    border-top: 1px solid var(--border);
}

.word-inspector h4 {
    font-size: 12px;
    color: var(--accent);
    margin-bottom: 6px;
    font-weight: 600;
}

.word-thread, .prim-disasm {
    font-size: 12px;
}

.thread-entry {
    display: flex;
    gap: 8px;
    padding: 1px 4px;
}

.thread-addr {
    color: var(--dim);
    flex-shrink: 0;
}

.thread-name {
    color: var(--text);
}

.word-inspector-empty {
    padding: 12px 8px;
    color: var(--dim);
    font-size: 12px;
    font-style: italic;
}

/* Compile log */
.compile-log {
    padding: 8px;
    max-height: 300px;
    overflow-y: auto;
    font-size: 11px;
}

.log-line {
    display: flex;
    gap: 8px;
    padding: 1px 4px;
    line-height: 1.5;
}

.log-line.log-label-line {
    margin-top: 4px;
}

.log-addr {
    color: var(--dim);
    flex-shrink: 0;
    min-width: 48px;
}

.log-bytes {
    color: var(--yellow);
    flex-shrink: 0;
    min-width: 110px;
    font-size: 10px;
}

.log-source {
    color: var(--text);
    white-space: pre;
    overflow: hidden;
    text-overflow: ellipsis;
}

.log-label-line .log-source {
    color: var(--accent);
}

